<?php
namespace App\Controllers;
use App\Core\Auth;use App\Core\Database;use App\Core\View;use App\Services\AuditService;
final class EntityApprovalController{
 public function index():void{Auth::requireLogin();$pdo=Database::connection();$rows=$pdo->query("SELECT a.*,r.name rule_name,u.name requester,d.name decider,CASE WHEN a.entity_type='estimate' THEN (SELECT estimate_number FROM estimates WHERE id=a.entity_id) ELSE (SELECT job_number FROM jobs WHERE id=a.entity_id) END reference FROM entity_approvals a LEFT JOIN approval_rules r ON r.id=a.approval_rule_id LEFT JOIN users u ON u.id=a.requested_by LEFT JOIN users d ON d.id=a.decided_by ORDER BY a.requested_at DESC")->fetchAll();View::render('portal/entity-approvals/index',['title'=>'Estimate & Job Approvals','rows'=>$rows,'rules'=>$pdo->query('SELECT * FROM approval_rules ORDER BY entity_type,name')->fetchAll()],'portal');}
 public function rule():void{Auth::requireRole('owner','administrator');verify_csrf();Database::connection()->prepare('INSERT INTO approval_rules(name,entity_type,trigger_field,operator,threshold_value,required_role,active) VALUES(?,?,?,?,?,?,?)')->execute([trim($_POST['name']),$_POST['entity_type'],trim($_POST['trigger_field']??'total'),$_POST['operator'],($_POST['threshold_value']??'')?:null,$_POST['required_role'],isset($_POST['active'])?1:0]);flash('success','Approval rule created.');redirect('/portal/entity-approvals');}
 public function decide(int $id):void{Auth::requireLogin();verify_csrf();$status=in_array($_POST['status']??'', ['approved','rejected'],true)?$_POST['status']:'rejected';$pdo=Database::connection();$s=$pdo->prepare('SELECT assigned_role FROM entity_approvals WHERE id=?');$s->execute([$id]);$role=$s->fetchColumn();if($role&&!Auth::can($role,'administrator')){http_response_code(403);exit('Approval role required.');}$pdo->prepare('UPDATE entity_approvals SET status=?,decided_by=?,decision_note=?,decided_at=NOW() WHERE id=?')->execute([$status,Auth::id(),trim($_POST['decision_note']??''),$id]);AuditService::log('entity_approval.'.$status,'entity_approval',$id);flash('success','Approval decision recorded.');redirect('/portal/entity-approvals');}
}
